1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it.todo("two adjacent cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []");
12	  it("live cell with 2 neighbors survives (rule 2 - survival)", () => {
13	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
14	    expect(result).toContainEqual([1, 0]);
15	  });
16	  it("live cell with 3 neighbors survives (rule 2 - survival)", () => {
17	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
18	    expect(result).toContainEqual([0, 0]);
19	  });
20	  it("live cell with 4 neighbors dies (rule 3 - overpopulation)", () => {
21	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it.todo("dead cell with exactly 3 neighbors becomes alive (rule 4 - reproduction) — [(0,0),(1,0),(0,1)] produces (1,1)");
25	  it.todo("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same");
26	  it.todo("blinker vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
27	  it.todo("handles negative coordinates correctly");
28	});
29

1	// A live cell's coordinates as [x, y]. The grid is unbounded;
2	// coordinates may be negative.
3	export type Cell = [number, number];
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const cellKey = (x: number, y: number): string => `${x},${y}`;
12	
13	const countLiveNeighbors = (
14	  x: number,
15	  y: number,
16	  liveSet: ReadonlySet<string>,
17	): number =>
18	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(cellKey(x + dx, y + dy)))
19	    .length;
20	
21	export function nextGeneration(liveCells: Cell[]): Cell[] {
22	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
23	  return liveCells.filter(([x, y]) => {
24	    const neighbors = countLiveNeighbors(x, y, liveSet);
25	    return neighbors === 2 || neighbors === 3;
26	  });
27	}
